abstract class Logger {
  // Abstract method — subclass MUST implement; no body here
  abstract write(message: string): void;

  // Concrete methods — shared by all subclasses; call abstract write()
  info(message: string):  void { this.write(`[INFO]  ${message}`); }
  warn(message: string):  void { this.write(`[WARN]  ${message}`); }
  error(message: string): void { this.write(`[ERROR] ${message}`); }
}

class ConsoleLogger extends Logger {
  override write(message: string): void {
    console.log(message);
  }
}

class NoopLogger extends Logger {
  override write(_message: string): void { /* discard — for tests */ }
}

// const bad = new Logger(); // Error: Cannot create an instance of an abstract class.

const logger: Logger = new ConsoleLogger(); // valid — Logger is a type
logger.info('Server started');   // [INFO]  Server started
logger.error('Disk full');       // [ERROR] Disk full

abstract class Report {
  // Abstract property — value computed by each subclass
  abstract readonly title: string;

  // Abstract method — each subclass renders data differently
  abstract render(data: unknown[]): string;

  // Concrete method — shared report structure
  generate(data: unknown[]): string {
    return [
      `=== ${this.title} ===`,
      this.render(data),
      `Generated: ${new Date().toLocaleDateString()}`,
    ].join('
');
  }
}

class CsvReport extends Report {
  override readonly title = 'CSV Export';

  override render(data: unknown[]): string {
    return data.map(row => JSON.stringify(row)).join('
');
  }
}

class HtmlReport extends Report {
  override readonly title = 'HTML Report';

  override render(data: unknown[]): string {
    const rows = data.map(row => `<tr><td>${JSON.stringify(row)}</td></tr>`).join('');
    return `<table>${rows}</table>`;
  }
}

const csv  = new CsvReport();
const html = new HtmlReport();

const data = [{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }];
console.log(csv.generate(data));
console.log(html.generate(data));

// Interface — purely structural, erased at runtime
interface Printable {
  print(): void;
}

// Abstract class — has runtime presence, can share logic
abstract class PrintableBase {
  private printCount = 0; // field with initialiser — not possible in interface

  abstract getContent(): string; // contract

  print(): void {
    this.printCount++;
    console.log(`[${this.printCount}] ${this.getContent()}`);
  }
}

// When to choose:
// Interface  → you only need a type contract; classes from unrelated hierarchies will implement it
// Abstract class → you need shared implementation, private state, or constructor logic

import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, catchError, throwError } from 'rxjs';

// Shared error handling and request setup
abstract class BaseApiService {
  protected readonly http = inject(HttpClient);
  protected abstract readonly baseUrl: string;

  // Abstract — subclass decides the resource path
  protected abstract resourcePath(): string;

  protected get url(): string { return `${this.baseUrl}/${this.resourcePath()}`; }

  // Concrete — shared error handler
  protected handleError(error: unknown): Observable<never> {
    const message = error instanceof Error ? error.message : 'Unknown API error';
    console.error(`[${this.resourcePath()}]`, message);
    return throwError(() => new Error(message));
  }
}

interface Product { id: number; name: string; price: number }

@Injectable({ providedIn: 'root' })
class ProductService extends BaseApiService {
  protected override readonly baseUrl = 'https://api.example.com';
  protected override resourcePath(): string { return 'products'; }

  getProducts(): Observable<Product[]> {
    return this.http.get<Product[]>(this.url).pipe(
      catchError(err => this.handleError(err)),
    );
  }
}

import { AbstractControl, ValidationErrors, ValidatorFn } from '@angular/forms';

// Abstract validator base — Template Method for form validators
abstract class BaseValidator {
  // Subclass provides the check logic
  protected abstract validate(value: string): boolean;

  // Concrete factory method — wraps the check as a ValidatorFn
  toValidatorFn(errorKey: string): ValidatorFn {
    return (control: AbstractControl): ValidationErrors | null => {
      const value = control.value;
      if (value === null || value === undefined || value === '') return null;
      const isValid = this.validate(String(value));
      return isValid ? null : { [errorKey]: true };
    };
  }
}

class EmailValidator extends BaseValidator {
  protected override validate(value: string): boolean {
    return /^[^@]+@[^@]+\.[^@]+$/.test(value);
  }
}

class MinLengthValidator extends BaseValidator {
  constructor(private readonly min: number) { super(); }
  protected override validate(value: string): boolean { return value.length >= this.min; }
}

// Usage
const emailFn     = new EmailValidator().toValidatorFn('email');
const minLengthFn = new MinLengthValidator(8).toValidatorFn('minlength');

// Apply to a FormControl
import { FormControl } from '@angular/forms';
const emailControl = new FormControl('', [emailFn]);
const pwdControl   = new FormControl('', [minLengthFn]);

import { Injectable, inject } from '@angular/core';

// Abstract class as a DI token and contract
abstract class StorageAdapter {
  abstract get(key: string): string | null;
  abstract set(key: string, value: string): void;
  abstract remove(key: string): void;
}

@Injectable()
class LocalStorageAdapter extends StorageAdapter {
  override get(key: string): string | null    { return localStorage.getItem(key); }
  override set(key: string, value: string): void { localStorage.setItem(key, value); }
  override remove(key: string): void          { localStorage.removeItem(key); }
}

@Injectable()
class InMemoryStorageAdapter extends StorageAdapter {
  private readonly store = new Map<string, string>();
  override get(key: string): string | null    { return this.store.get(key) ?? null; }
  override set(key: string, value: string): void { this.store.set(key, value); }
  override remove(key: string): void          { this.store.delete(key); }
}

// Consumer depends on the abstract class
@Injectable({ providedIn: 'root' })
class CacheService {
  private readonly storage = inject(StorageAdapter);

  cache(key: string, value: string): void { this.storage.set(key, value); }
  recall(key: string): string | null       { return this.storage.get(key); }
}

// Swap implementation via providers without changing CacheService
// { provide: StorageAdapter, useClass: LocalStorageAdapter }   // prod
// { provide: StorageAdapter, useClass: InMemoryStorageAdapter } // test

abstract class DataExporter {
  // Template method — the algorithm skeleton (not abstract, not overridable)
  final export(data: unknown[]): string {
    const validated = this.validate(data);     // step 1 — abstract
    const transformed = this.transform(validated); // step 2 — abstract
    const output = this.serialize(transformed);    // step 3 — abstract
    this.onComplete(output);                       // step 4 — concrete hook
    return output;
  }

  protected abstract validate(data: unknown[]): unknown[];
  protected abstract transform(data: unknown[]): unknown[];
  protected abstract serialize(data: unknown[]): string;

  // Hook method — concrete default, subclass may override
  protected onComplete(output: string): void {
    console.log(`Exported ${output.length} bytes`);
  }
}

class CsvExporter extends DataExporter {
  protected validate(data: unknown[]) { return data.filter(Boolean); }
  protected transform(data: unknown[]) { return data.map(r => Object.values(r as object)); }
  protected serialize(rows: unknown[]) { return (rows as string[][]).map(r => r.join(',')).join('\n'); }
}

class JsonExporter extends DataExporter {
  protected validate(data: unknown[]) { return data; }
  protected transform(data: unknown[]) { return data; }
  protected serialize(data: unknown[]) { return JSON.stringify(data, null, 2); }
  // Overrides onComplete hook to suppress log
  protected override onComplete(_: string): void {}
}

const csv = new CsvExporter();
csv.export([{ name: 'Alice', age: 30 }]); // calls template method

abstract class Cache<K, V> {
  private store = new Map<K, V>();

  // Abstract: how to load a missing value
  protected abstract load(key: K): Promise<V>;

  async get(key: K): Promise<V> {
    if (this.store.has(key)) {
      return this.store.get(key)!;
    }
    const value = await this.load(key);
    this.store.set(key, value);
    return value;
  }

  invalidate(key: K): void { this.store.delete(key); }
  clear(): void { this.store.clear(); }
}

class UserCache extends Cache<string, User> {
  constructor(private http: HttpClient) { super(); }

  protected override async load(id: string): Promise<User> {
    return this.http.get<User>(\`/api/users/\${id}\`).toPromise()!;
  }
}

abstract class Base {
  constructor() {
    // BAD — subclass constructor body hasn't run yet
    this.init(); // calls abstract method too early
  }
  abstract init(): void;
}

class Child extends Base {
  private value = 42; // set AFTER super() completes
  override init(): void { console.log(this.value); } // logs undefined, not 42
}

// Safe alternative: factory method or ngOnInit lifecycle hook
abstract class SafeBase {
  // Let the consumer call init() after construction
  abstract init(): void;
}

// abstract-logger.spec.ts
import { Logger } from './logger';

// Minimal concrete subclass used only in tests
class TestLogger extends Logger {
  readonly lines: string[] = [];
  override write(message: string): void { this.lines.push(message); }
}

describe('Logger (abstract)', () => {
  let logger: TestLogger;

  beforeEach(() => { logger = new TestLogger(); });

  it('prefixes info messages', () => {
    logger.info('hello');
    expect(logger.lines[0]).toBe('[INFO]  hello');
  });

  it('prefixes error messages', () => {
    logger.error('boom');
    expect(logger.lines[0]).toBe('[ERROR] boom');
  });
});

// Abstract base — shared pagination
abstract class PaginatedService<T> {
  abstract endpoint(): string;
  getPage(page: number, size: number): Observable<T[]> {
    return this.http.get<T[]>(\`\${this.endpoint()}?page=\${page}&size=\${size}\`);
  }
  constructor(protected http: HttpClient) {}
}

// Concrete service
@Injectable({ providedIn: 'root' })
class ProductService extends PaginatedService<Product> {
  override endpoint() { return '/api/products'; }
}

// Spec — TestBed wires it like any service
describe('ProductService', () => {
  let service: ProductService;
  let httpMock: HttpTestingController;

  beforeEach(() => {
    TestBed.configureTestingModule({ imports: [HttpClientTestingModule] });
    service = TestBed.inject(ProductService);
    httpMock = TestBed.inject(HttpTestingController);
  });

  it('requests the correct endpoint', () => {
    service.getPage(1, 10).subscribe();
    const req = httpMock.expectOne('/api/products?page=1&size=10');
    expect(req.request.method).toBe('GET');
    req.flush([]);
  });
});
